def circular_shift(x, shift):
    """See the attached image for the function's specification."""
    num_digits = len(str(abs(x)))
    shift = shift % num_digits
    if x < 0:
        sign = -1
        x = abs(x)
    else:
        sign = 1
    shifted_str = str(x)[-shift:] + str(x)[:-shift]
    return sign * int(shifted_str)
