from typing import List, Optional

def longest(strings: List[str]) -> Optional[str]:
    if not strings:
        return None
    longest_str = strings[0]
    for s in strings[1:]:
        if len(s) > len(longest_str):
            longest_str = s
        elif len(s) == len(longest_str):
            if s not in strings[:strings.index(s)+1]:
                longest_str = s
    return longest_str
```

