def correct_bracketing(brackets: str) -> bool:
    """
    Checks if the input string of brackets is correctly bracketed.

    A string of brackets is considered correctly bracketed if every opening bracket has a corresponding closing bracket.

    Parameters:
    brackets (str): The input string of brackets.

    Returns:
    bool: True if the input string is correctly bracketed, False otherwise.
    """
    stack = []
    bracket_map = {')': '(', '}': '{', ']': '['}

    for bracket in brackets:
        if bracket in bracket_map.values():
            stack.append(bracket)
        elif bracket in bracket_map.keys():
            if stack == [] or bracket_map[bracket] != stack.pop():
                return False

    return stack == []
```

