def encode(message):
    """
    Write a function that takes a message, and encodes in such a way that it swaps case of all letters, 
    replaces all vowels in the message with the letter that appears 2 places ahead of that vowel in the english alphabet.
    Assume only letters.
    """
    vowels = 'aeiouAEIOU'
    encoded_message = ''

    for char in message:
        if char.isalpha():
            if char in vowels:
                # Find the position in the alphabet for the vowel
                position = ord(char.lower()) - ord('a')
                # Calculate the new position, wrapping around the alphabet if necessary
                new_position = (position + 2) % 26
                # Convert the new position back to a character
                new_char = chr(new_position + ord('a'))
                # Preserve the original case
                if char.isupper():
                    encoded_message += new_char.upper()
                else:
                    encoded_message += new_char
            else:
                # Swap the case of the character
                if char.isupper():
                    encoded_message += char.lower()
                else:
                    encoded_message += char.upper()
        else:
            encoded_message += char

    return encoded_message
